head.script:
scwin.memJson = $c.data.getMemInfo();
scwin.userId = scwin.memJson.userId;
scwin.userType = scwin.memJson.userClsCd;
scwin.userHomeClsCd = scwin.memJson.userHomeClsCd;
scwin.coCd = scwin.memJson.coCd;
scwin.sysAdminYn = scwin.memJson.sysAdminYn;
scwin.currDate = WebSquare.date.getFormattedDate (new Date(), "yyyyMMdd");

console.log("##### userId : " + scwin.userId);
console.log("##### userType : " + scwin.userType);
console.log("##### userHomeClsCd : " + scwin.userHomeClsCd);
console.log("##### coCd : " + scwin.coCd);
console.log("##### sysAdminYn : " + scwin.sysAdminYn);

//hidden start
scwin.txt_userClsCd = "";
scwin.txt_countRow = "";
scwin.txt_checkUserDupl = "";
scwin.txt_SaveType = "";
scwin.txt_curDate = scwin.currDate;
scwin.value_useYn = "";
scwin.value_blockReason = "";
scwin.value_blockDt = "";
scwin.value_blockEtDt = "";
scwin.value_blockCancelEtDt = "";
//hidden end


////As-is///////////////////////////////////////////////////////////////////////
scwin.pos_rowSts = 0;
// var scwin.sysAdminYn = "<%=sysAdminYn%>";
scwin.editYn = 0;
scwin.flag = 0;
scwin.row_confirm;
scwin.isFirst = 1;


scwin.onpageload = function() {
    const codeOptions = [ 
        { grpCd : "ZZ010", compID : "lc_userClsCd_param,lc_userClsCd, gr_user:userClsCd" },
        { grpCd : "ZZ002", compID : "lc_blockReason_param,lc_blockReason" },
        { grpCd : "ZZ011", compID : "lc_basisMenuClsCd" },
        { grpCd : "ZZ020", compID : "lc_lobranPrivLvl,lc_exprOfcPrivLvl,lc_rentcarOfcPrivLvl,lc_fixWrkPlPrivLvl,lc_acctDeptPrivLvl" },
        { grpCd : "ZZ019", compID : "lc_userHomeClsCd" },
    ];
    $c.data.setCommonCode(codeOptions);
};

scwin.onUdcCompleted = function() {
};

scwin.ondataload = function(e) {

    scwin.f_ContentsDisable();
    rd_useYn_param.setValue("1");
    lc_userClsCd_param.setSelectedIndex(0);
    $c.gus.cfDisableBtn([btn_Update, btn_Cancel, btn_Save, btn_AddRow, btn_DeleteRow, btn_UndoRow]);

    ed_zip.setEditFormat('###-#||###-##||###-###');// -를 자리수 로 먹어서 maxLength 6-> 7

    const codeOptions = [
        { method: "getLuxeComboData"
        , param1: "PsCommonEBC"
        , param2: "retrieveRentBranchList"
        , compID: "lc_rentcarOfcCd"
        },
    ];
    $c.data.setGauceUtil(codeOptions);

    if( $p.getAllParameter().paramData.menuInfo.menuId.indexOf("n") > -1){
        rd_debis.setSelectedIndex(1);
        rd_debis.setDisabled(true);
    }
};

scwin.init = function() {
    let vparam1 = "";
    if(rd_debis.getValue() == "N") {
        vparam1 = "Ncall";
    }

    ds_user.setJSON([]);
    ds_userPrivGroup.setJSON([]);

    spanTotal.setLabel(0);
    spanTotal2.setLabel(0);
};


