//-------------------------------------------------------------------------
// function name : f_Addrow
// function desc : 그리드 칼럼 추가
//-------------------------------------------------------------------------
scwin.f_Addrow = async function() {
    let row ;
    row = ds_user.insertRow();
    ds_user.setRowPosition(row);

    ed_empNm.setValue("");
    ed_clntNm.setValue("");

    ds_user.setCellData( row , "useYn", 1 );

    gr_user.setFocusedCell(row, 0);
};

//-------------------------------------------------------------------------
// function name : f_Retrieve
// function desc : 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = function() {
    scwin.flag = 0;
    dma_search.set("empNo", ed_empNo_param.getValue());
    dma_search.set("userId", ed_userId_param.getValue());
    dma_search.set("userNm", ed_userNm_param.getValue());
    dma_search.set("clntNo", ed_clntNo_param.getValue());
    let debis = "";
    if(rd_debis.getValue() == "N") {
        debis = "ncall.";
    }
    sbm_retrieve.action = "/"+debis+"cm.bc.comnmgnt.usermgnt.cmd.RetrieveUserListCMD.do";
    $c.sbm.execute(sbm_retrieve);
};

scwin.sbm_retrieve_submitdone = async function (e) {
    //gr_user.setFocusedCell(0, 0);
    var rowCnt = ds_user.getRowCount();
    spanTotal.setLabel(rowCnt);
    scwin.txt_countRow = rowCnt;

    var vPasswordExceptYn = cbx_passwordExceptYn.getValue();

    if (rowCnt == 0) {
        $c.gus.cfAlertMsg($p, MSG_CM_WRN_002); // 조회결과가 존재하지 않습니다
        $c.gus.cfDisableBtn([btn_Save, btn_Cancel, btn_AddRow, btn_DeleteRow, btn_UndoRow]);
    } else {
        scwin.f_ContentsDisable();
        if(vPasswordExceptYn != "0"){
            $c.gus.cfDisableBtn([btn_Create, btn_Update, btn_Cancel]);

            scwin.f_ContentsDisable();
            ed_newPasswd.setDisabled(false);
            ed_newPasswdConfirm.setDisabled(false);
            $c.gus.cfDisableBtn([btn_Create, btn_Update]);

        }else{
            $c.gus.cfDisableBtn([btn_Save, btn_Cancel, btn_AddRow, btn_DeleteRow, btn_UndoRow]);
        }
        gr_user.setFocusedCell(scwin.pos_rowSts, 0);
    }

    ed_newPasswd.setMandatory(false);
    ed_newPasswdConfirm.setMandatory(false);

    gr_userPrivGroup.setReadOnly(true);
    // cfRefreshMandSign();

	scwin.txt_checkUserDupl = ""; // 사용자ID 유효성체크 
	ds_user.modifyAllStatus("R");
};

scwin.ds_user_onrowpositionchange = function (info) {
    let row = info.newRowIndex;
    let SysStatus = ds_user.getRowStatus(row);
    var userClsCd = ds_user.getCellData(row,'userClsCd');

    //0: Normal, 1: Insert, 2: Delete, 3: Update, 4: Logical
    if(SysStatus == "U"){
        ed_newPasswd.setMandatory(false);
        ed_newPasswdConfirm.setMandatory(false);

        //$c.gus.cfRefreshMandSign();
    }

    if(ds_user.getRowCount() > 0){
        scwin.f_RetrieveUserPriv();
    }

    ed_newPasswdConfirm.setValue("");
};

//-------------------------------------------------------------------------
// function name : f_RetrieveUserPriv
// function desc : 조회
//-------------------------------------------------------------------------
scwin.f_RetrieveUserPriv = function() {
    let rowIndex = ds_user.getRowPosition();
    let debis = "";
    if(rd_debis.getValue() == "N") {
        debis = "ncall.";
    }
    sbm_userPrivGroup.action = "/"+debis+"cm.bc.comnmgnt.usermgnt.cmd.RetrieveUserPrivilegeGroupListCMD.do";
    $c.sbm.execute(sbm_userPrivGroup, {"userId":ds_user.getCellData( rowIndex, "userId" )});
};

//-------------------------------------------------------------------------
// function name : f
// function desc : 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function() { 
    var vUserClsCd = scwin.txt_userClsCd;
    var vUserId = ed_userId.getValue().trimAll();
    var vCheckUserIdSearchYn = scwin.txt_checkUserDupl;
    // var vRowStatus = oGDS_search_cond.RowStatus(oGDS_search_cond.RowPosition);
    var vPasswordExceptYn = cbx_passwordExceptYn.getValue();
    var vNewPassword = ed_newPasswd.getValue();
    var vNewPasswordConfirm = ed_newPasswdConfirm.getValue();
    var rowIndex = ds_user.getRowPosition();
    var vUserRowStatus = ds_user.getRowStatus(rowIndex);

    if ( !scwin.f_userIdCheck(vUserId) ){
        ed_userId.focus();
        return false;
    }

    if ( !scwin.f_passwordCheck(vUserId,vNewPassword) ){
        ed_newPasswd.focus();
        return false;
    }

    //0: Normal, 1: Insert, 2: Delete, 3: Update, 4: Logical
    // 사용자 등록인 경우만 비밀번호 필수
    // if(vUserRowStatus==1){
    if(vUserRowStatus == "C"){
        ed_newPasswd.setMandatory(true);
        ed_newPasswdConfirm.setMandatory(true);
    }else if(vUserRowStatus == "U"){
        ed_newPasswd.setMandatory(false);
        ed_newPasswdConfirm.setMandatory(false);
    }

    if(vPasswordExceptYn == "1"){     
        if(vNewPassword != vNewPasswordConfirm){
            await $c.win.alert("신규비밀번호와 신규확인번호는 일치해야합니다.");
            ed_newPasswdConfirm.focus();
            return false;
        }
    }else{ 
        if(vNewPassword.trimAll()!=""){
            if(vNewPassword != vNewPasswordConfirm){
                await $c.win.alert("신규비밀번호와 신규확인번호는 일치해야합니다.");
                ed_newPasswdConfirm.focus();
                return false;
            }
        }
    }

    for(var i=0; i<ds_user.getRowCount(); i++) {
        var rowJson = ds_user.getRowJSON(i);
        var rowSts = ds_user.getRowStatus(i); // 첫 번째 행의 rowStatus 값(문자)를 반환한다.
        //0: Normal, 1: Insert, 2: Delete, 3: Update, 4: Logical
        if( rowSts == "U"  || rowSts == "C" ) {
            // 아이디 계정 차단 관련

            if( rowSts == "U" )	{
                scwin.value_useYn				= 	rowJson.useYn;
                scwin.value_blockReason			=	rowJson.blockReason;
                scwin.value_blockDt				=	rowJson.blockDt;
                scwin.value_blockEtDt		    =	rowJson.blockEtDt;
                scwin.value_blockCancelEtDt		=	rowJson.blockCancelEtDt;

            }else if( rowSts == "C" )	{
                scwin.value_useYn				= 	scwin.selUseYn;
                scwin.value_blockReason			=	lc_blockReason.getValue();
                scwin.value_blockDt				=	ica_blockDt.getValue();
                scwin.value_blockEtDt		    =	ica_blockEtDt.getValue();
                scwin.value_blockCancelEtDt		=	ica_blockCancelEtDt.getValue();
            }
            if(scwin.value_useYn			== "2")	{
                await $c.win.alert("사용여부를 선택해야 합니다.");
                return false;
            }

            // if(scwin.value_blockDt != "" || scwin.value_blockEtDt != "" || scwin.value_blockCancelEtDt != "" || scwin.value_useYn == 0 )	{
            if(scwin.value_blockDt != "" || scwin.value_blockEtDt != "" || scwin.value_blockCancelEtDt != "" || scwin.value_useYn == "0" )	{
                if(scwin.value_blockReason == "")	{
                    await $c.win.alert("차단을 하거나 차단예정일자를 지정하는 경우에는 차단 사유를 입력해야 합니다.");
                    return false;
                }
            }
            if(scwin.value_useYn == "1")	{
                var reason = scwin.value_blockReason;
                if(scwin.value_blockDt != "") {
                    $c.win.alert("사용여부 Yes인 상태에서 차단일자를 설정할 수 없습니다.");
                    return false;
                }	
                if(scwin.value_blockEtDt == "" && scwin.value_blockReason != "") {
                    $c.win.alert("사용여부 Yes인 상태에서는 차단예정일자를 설정해야 합니다.");
                    return false;
                }								
                if(scwin.value_blockReason == "C" || scwin.value_blockReason == "D" )	{
                    if(reason == "C")
                        $c.win.alert("사용여부 Yes인 상태에서 비밀번호 오류를 차단사유로 사용할 수 없습니다.");
                    else if(reason == "D")
                        $c.win.alert("사용여부 Yes인 상태에서 비밀번호 만기를 차단사유로 사용할 수 없습니다.");
                    return false;
                }
                if(scwin.value_blockReason == "A" || scwin.value_blockReason == "B" )	{
                    if(scwin.value_blockEtDt == "")	{
                        $c.win.alert("차단예정일자가 필요합니다.");
                        return false;
                    }
                }
                if(scwin.value_blockReason == "E" )	{
                    if(scwin.value_blockEtDt == "")	{		
                        $c.win.alert("차단예정일자가 필요합니다.");
                        return false;
                    }
                }
            }

            //날짜 입력 오류 검사 관련 부분
            //scwin.txt_curDate = <%= strCurDate %>; 
            if( scwin.value_blockEtDt != "")	{
                if (!$c.gus.cfIsAfterDate(scwin.txt_curDate, scwin.value_blockEtDt) || scwin.txt_curDate == scwin.value_blockEtDt ) {
                    $c.win.alert("차단예정일자는 현재 날짜 이후로 입력해 주십시오.");
                    ica_blockDt.setValue("");
                    ica_blockEtDt.setValue("");
                    ica_blockCancelEtDt.setValue("");
                    //PAGE_MOVE_CONFIRM = false;
                    return false;
                }
            }

            if( scwin.value_blockCancelEtDt != "")	{
                if (!$c.gus.cfIsAfterDate(scwin.txt_curDate, scwin.value_blockCancelEtDt) || scwin.txt_curDate == scwin.value_blockCancelEtDt ) {
                    $c.win.alert("차단해지예정일자를 현재 날짜 이후로 입력해 주십시오.");
                    ica_blockDt.setValue("");
                    ica_blockEtDt.setValue("");
                    ica_blockCancelEtDt.setValue("");				
                    //PAGE_MOVE_CONFIRM = false;
                    return false;
                }
            }				
            if( scwin.value_blockDt != "")	{
                if($c.gus.cfIsAfterDate(scwin.txt_curDate, scwin.value_blockDt) && scwin.txt_curDate != scwin.value_blockDt )	{
                    $c.win.alert("차단일자는 현재일자까지만 입력이 가능합니다");
                    ica_blockDt.setValue("");
                    ica_blockEtDt.setValue("");
                    ica_blockCancelEtDt.setValue("");
                    return false;
                }
            }
            if( (scwin.value_blockEtDt != "")  &&  (scwin.value_blockDt != "") )	{		// 차단일자와 차단 예정 일자 동시에 설정할 수 없다.		
                $c.win.alert("차단일자와 차단예정일자를 동시에 설정할 수 없습니다.");	
                ica_blockDt.setValue("");
                ica_blockEtDt.setValue("");
                ica_blockCancelEtDt.setValue("");					
                return false;
            }

            if( (scwin.value_blockEtDt != "")  &&  (scwin.value_blockCancelEtDt != "") )	{		// 차단해지 예정 일자는  차단 예정 일자를 이후여야 한다..
                if (!$c.gus.cfIsAfterDate(scwin.value_blockEtDt, scwin.value_blockCancelEtDt))		{
                    $c.win.alert("차단 예정 일자를 해지 일자 이전으로 입력해 주십시오.");	
                    ica_blockDt.setValue("");
                    ica_blockEtDt.setValue("");
                    ica_blockCancelEtDt.setValue("");					
                    return false;
                }
            }					
        }
    }

    if(vUserRowStatus == "C" || vUserRowStatus == "U"){
  	    if(! await $c.gus.cfValidate([oRecevInfo])){
		    return false;
 		}
    }

    var vUserPrivGroupDuplCheck = scwin.f_ChkUserPrivGroupSelect();
    if(vUserPrivGroupDuplCheck){
        await $c.win.alert("사용자권한그룹이 중복되었습니다.");
        // gr_userPrivGroup.Focus();
        return false;
    }

    console.log(4);
    var ds_userModi = ds_user.getModifiedJSON();
    var ds_userPrivGroupModi = ds_userPrivGroup.getModifiedJSON();
    console.log("====jsonData.length =="+ds_userModi.length);

    if( (ds_userModi.length == 0) && (ds_userPrivGroupModi.length == 0) ) {
        await $c.win.alert($c.data.getMessage(MSG_CM_ERR_001, "사용자 정보"));
    } else {	          
        scwin.pos_rowSts = ds_user.getRowPosition();
        //0: Normal, 1: Insert, 2: Delete, 3: Update, 4: Logical
        if(vUserRowStatus == "C"){
            scwin.txt_SaveType = "1";
        } else if(vUserRowStatus == "U"){            
            scwin.txt_SaveType = "3";
        }

        let confirmResult = await $c.win.confirm(MSG_CM_CRM_001);
        if (confirmResult) {
            ds_userPrivGroup.setCellData(0, "userId", ed_userId.getValue());
            let debis = "";
            if(rd_debis.getValue() == "N") {
                debis = "ncall.";
            }
            sbm_save.action = "/"+debis+"cm.bc.comnmgnt.usermgnt.cmd.SaveUserCMD.do";
            $c.sbm.execute(sbm_save);
			// scwin.f_Retrieve();
			// scwin.f_ContentsDisable();
			scwin.flag = 0;            
        } else {
            scwin.f_Cancel();
        }

    } 
}; 

//scwin.f_userIdCheck(vUserId){
scwin.f_userIdCheck = function(vUserId) {
    // var vUserClsCd = scwin.txt_userClsCd;
    console.log("=======vUserId=22=="+vUserId.length);
    var iLen = vUserId.length ;	

    // var vFirstChar = vUserId.substr(0,1); 
    var engCnt = $c.gus.cfisEnglishCnt(vUserId) ;
    var numCnt = $c.gus.cfisNumberCnt(vUserId) ;

    if ( iLen < 4 ){
          $c.win.alert("사용자ID는 4자리 이상이어야 합니다.");
          return false;
    }

    if ( (engCnt + numCnt) != iLen ) {
        $c.win.alert("사용자ID는 특수문자를 사용할수 없습니다.");
        return false;
    }
    return true;
};

scwin.f_passwordCheck = function(vUserId, vPassword){
    var iLen = vPassword.length ;	
    var engCnt = $c.gus.cfisEnglishCnt(vPassword) ;
    var numCnt = $c.gus.cfisNumberCnt(vPassword) ;

    var vPasswordExceptYn = cbx_passwordExceptYn.getValue();

    // if ( !passwordExceptYn.checked && vPassword == "" ) return true ;
    if ( !(vPasswordExceptYn=="1") && vPassword == "" ) return true ;

    if ( $c.gus.cfnumChainChk(vPassword) ) {
        $c.win.alert("비밀번호는 연속 또는 동일한  숫자 3자리 이상  사용할 수 없습니다.");
        return false;
    }

    if ( iLen < 4 ){
        $c.win.alert("비밀번호는 4자리 이상이어야 합니다.");
        return false;
    }

    if ( engCnt == 0 || numCnt == 0 )
    {
        $c.win.alert("비밀번호는 영어+숫자 조합이어야 합니다.");
        return false;
    } 

    if ( vUserId == vPassword )
    {
        $c.win.alert("사용자ID를 비밀번호로 사용할  수  없습니다.");
        return false;
    } 
    return true;
};

scwin.f_dataSetClear = function() {
