    var vDataSetCountRow = ds_user.CountRow;

    if(vPasswordExceptYn==false && vDataSetCountRow>0){
        ds_user.ClearData();
    }
};

//-------------------------------------------------------------------------
// 신규
//-------------------------------------------------------------------------
scwin.f_Create = function() {
    scwin.flag = 1;
    scwin.f_Addrow();
    //rd_useY.checked = true;
    //rd_useYn.setValue("1");
    scwin.selUseYn = 1;
    scwin.f_ContentsEnable();

    // gr_userPrivGroup.Editable = true;

    // lc_userClsCd.Index=0;
    lc_userClsCd.setSelectedIndex(0);
    lc_userHomeClsCd.setSelectedIndex(0);
    lc_basisMenuClsCd.setSelectedIndex(0);
    scwin.txt_checkUserDupl = "";
    if(scwin.sysAdminYn == "1"){
        rd_passwdExpyn.setDisabled(false);
    }else{
        rd_passwdExpyn.setDisabled(true);
    }
    rd_passwdExpyn.setSelectedIndex(1);
    rd_ssoAuthYn.setDisabled(false);
    rd_ssoAuthYn.setSelectedIndex(0);

    rd_sysAdminYn.setDisabled(false);
    rd_sysAdminYn.setSelectedIndex(1);

    rd_useYn.setDisabled(false);
    rd_useYn.setSelectedIndex(0);

    ed_newPasswd.mandatory="true";
    ed_newPasswdConfirm.mandatory="true";

    ////cfRefreshMandSign();

    $c.gus.cfDisableBtn([btn_Create, btn_Update]);

    scwin.editYn = 1;
};

//-------------------------------------------------------------------------
// 사용자 수정
//-------------------------------------------------------------------------
scwin.f_Update = function() {
    scwin.flag = 1;
    var vPasswordExceptYn = cbx_passwordExceptYn.getValue();

    if(scwin.sysAdminYn == "1"){
        rd_passwdExpyn.setDisabled(false);
    }else{
        rd_passwdExpyn.setDisabled(true);
    }

    if(vPasswordExceptYn == "1"){
        scwin.f_ContentsDisable();
        $c.gus.cfEnableObj(ed_newPasswd, true);	 //
        $c.gus.cfEnableObj(ed_newPasswdConfirm, true);	 //		

        $c.gus.cfDisableBtn([btn_Create, btn_Update]);
    }else{
        scwin.f_ContentsEnable();
        $c.gus.cfDisableBtn([btn_Create, btn_Update]);
    }
//     gr_userPrivGroup.Editable = true;
    // gr_userPrivGroup.setReadOnly(false);
    $c.gus.cfEnableObj(ed_userId, false);	 //
    scwin.txt_checkUserDupl = "";

    ed_newPasswd.setMandatory(false);
    ed_newPasswdConfirm.setMandatory(false);

    scwin.editYn = 0;

    $c.gus.cfDisableObjects([lc_blockReason, ica_blockDt, ica_blockCancelEtDt, ica_blockEtDt]);

    if(rd_useYn.getValue() == "0")	{
        if(lc_blockReason.getValue() == "A" || lc_blockReason.getValue() == "B")	{		
            $c.gus.cfEnableObjects([ica_blockDt, ica_blockCancelEtDt, lc_blockReason]);
        }else if(lc_blockReason.getValue() == "C" || lc_blockReason.getValue() == "D")	{	
            $c.gus.cfEnableObjects([lc_blockReason]);
        }else if(lc_blockReason.getValue() == "E")	{
            $c.gus.cfEnableObjects([ica_blockDt, lc_blockReason]);	
        }			
    }
    if(rd_useYn.getValue() == "1")	{
        $c.gus.cfEnableObjects([lc_blockReason, ica_blockCancelEtDt, ica_blockEtDt]);
    }
};

