scwin.f_Delete = function() {
    // ds_user.DeleteRow(ds_user.RowPosition);
    let row = ds_user.getRowPosition();
    if (ds_user.getRowStatus(row) == "C") {
        ds_user.removeRow(row);
    } else {
        ds_user.deleteRow(row);
    }
    gr_user.setFocusedCell(ds_user.getRowPosition(), "userId", true);
    $c.gus.cfDisableBtn([btn_Create, btn_Update, btn_Cancel]);
};

//-------------------------------------------------------------------------
//  사용자 행취소
//-------------------------------------------------------------------------
scwin.f_Undo = function() {
	// ds_user.Undo(ds_user.RowPosition);
	$c.data.undoRow(ds_user, "Y");
	if(ds_user.getRowCount() > 0) {
		$c.gus.cfDisableBtn([btn_Cancel, btn_Save]);
	}else{
		$c.gus.cfDisableBtn([btn_Cancel, btn_Save, btn_Update]);
	}
};

//-------------------------------------------------------------------------
// 사용자 등록, 수정 취소
//-------------------------------------------------------------------------
scwin.f_Cancel = function() {
    console.log("==================f_Cancel========");
    scwin.flag = 0;
    var vPasswordExceptYn = cbx_passwordExceptYn.getValue();

    scwin.f_ContentsDisable();
    scwin.txt_checkUserDupl = "";

    ed_newPasswd.setMandatory(false);			
    ed_newPasswdConfirm.setMandatory(false);			

    // cfRefreshMandSign();

    if(scwin.sysAdminYn == "1"){
        rd_passwdExpyn.setDisabled(false);
    }else{
        rd_passwdExpyn.setDisabled(true);
    }

    var vRowCount = scwin.txt_countRow;
    var vResultListPosition = ds_user.getRowPosition();

    // 20130327 변경
    var i;
    for( i=0 ; i < ds_user.getRowCount() ; i++) {
        //0: Normal, 1: Insert, 2: Delete, 3: Update, 4: Logical
        if(ds_user.getRowStatus(i) == "U" )	{
            ds_user.undoRow(i);
        }
        ed_newPasswdConfirm.setValue("");
    }
    for( i=0 ; i < ds_user.getRowCount() ; i++) {
        if(ds_user.getRowStatus(i) == "C" )	{
            ds_user.removeRow(i);
        }
        ed_newPasswdConfirm.setValue("");
    }	
    //20130327 변경

    ds_user.undoAll();
    ds_userPrivGroup.undoAll();
    if(vRowCount=="" || vRowCount=="0"){
        // 조회를 하지 않은 경우
        $c.gus.cfDisableBtn([btn_Cancel, btn_Save, btn_Update]);
    }else{
        // 조회를 한 경우
        if(vResultListPosition>=0){
            if(vPasswordExceptYn == "1"){
                $c.gus.cfDisableBtn([btn_Create, btn_Cancel, btn_Save]);				
            }else{
                $c.gus.cfDisableBtn([btn_Cancel, btn_Save, btn_AddRow, btn_DeleteRow, btn_UndoRow]);
            }
        }else{
          //   if(vPasswordExceptYn){
            if(vPasswordExceptYn == "1"){
                $c.gus.cfDisableBtn([btn_Create, btn_Cancel, btn_Save]);				
            }else{
                $c.gus.cfDisableBtn([btn_Cancel, btn_Save, btn_Update, btn_AddRow, btn_DeleteRow, btn_UndoRow]);

            }
        }
    }


    if( ds_user.getCellData(ds_user.getRowPosition(), "useYn") == 1)	{
        rd_useYn.setValue("1");
    } else {
        rd_useYn.setValue("0");
    }

};

