scwin.f_PrivAddRow = async function() {
    var vUserCountRow = ds_user.getRowCount();
    var vUserId = ds_user.getCellData(ds_user.getRowPosition(), "userId");

    if(vUserCountRow<1){
        await $c.win.alert("권한그룹을 추가할 사용자를 조회해 주십시오.");
        return false;
    }

    if(vUserId.trim()==""){
        await $c.win.alert("권한그룹을 추가할 사용자ID를 입력해주십시오.");
        ed_privGrpId.value = "";
        ed_userId.focus();
        return false;
    }	

    let rowIndex = ds_userPrivGroup.insertRow();
    // ds_userPrivGroup.NameString(ds_userPrivGroup.RowPosition, "userId") = oGDS_result_list.NameString(oGDS_result_list.RowPosition, "userId");	
    ds_userPrivGroup.setCellData(rowIndex, "userId", vUserId);
    gr_userPrivGroup.setCellReadOnly(rowIndex, "privGrpNm", false);
    gr_userPrivGroup.setFocusedCell(rowIndex, "privGrpId" , true );
};

