                                ,null					// Title순서	
                                ,null					// 보여주는 각 컬럼들의 폭	
                                ,null					// 컬럼중에서 숨기는	컬럼 지정	
                                ,null					// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
                                ,null					// POP-UP뛰을때 원도우의	사용자 정의	폭
                                ,null					// POP-UP뛰을때 우도우의	사용자 정의	높이	
                                ,null					// 윈도우 위치 Y좌표	
                                ,null					// 윈도우 위치 X좌표
                                ,null					// 중복체크여부	("F")
                                ,'F'					// 전체검색허용여부	("F")
                                ,"사원검색,사번,사원명"		// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
                                );

};

