//-------------------------------------------------------------------------
//  권한그룹 체크
//-------------------------------------------------------------------------
scwin.f_CheckPrivGrpGridRegist = async function() {
    var vPrivGroupId = ed_privGrpId.getValue();
    var vPrivGroupNm = ed_privGrpNm.getValue();

    if(vPrivGroupId.trim() != ""){
        var vPrivGrpCountRow = ds_userPrivGroup.getRowCount();
        var vDuplCount = 0;

        for(var i=0;i<vPrivGrpCountRow;i++){
            var vPrivGrpId = ds_userPrivGroup.getCellData(i, "privGrpId");
            if(vPrivGroupId==vPrivGrpId){
                vDuplCount++;
            }
        }

        if(vDuplCount>0){
            await $c.win.alert("이미 등록된 권한그룹입니다.");
            return false;
        }else{
            scwin.f_PrivAddRow();
            ds_userPrivGroup.setCellData(ds_userPrivGroup.getRowPosition(), "privGrpId", vPrivGroupId);
            ds_userPrivGroup.setCellData(ds_userPrivGroup.getRowPosition(), "privGrpNm", vPrivGroupNm);
        }
    }

};

