    for(var i=0; i<ds_userPrivGroup.getRowCount(); i++) {
        var rowJson = ds_userPrivGroup.getRowJSON(i);
        for(var j=(i+1); j<ds_userPrivGroup.getRowCount(); j++) {
            var rowJsonJ = ds_userPrivGroup.getRowJSON(j);
