scwin.sbm_save_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;
	await $c.gus.cfAlertMsg(MSG_CM_INF_001);	// 성공적으로 저장하였습니다 

	let vSaveType = scwin.txt_SaveType;
	let vCountRow = ds_user.getRowCount();
	let vPasswordExceptYn = cbx_passwordExceptYn.getValue();

	if(vSaveType=="1"){
		scwin.f_Retrieve();
	}else{
		if(vCountRow>0){
			// if(!vPasswordExceptYn){
            if(vPasswordExceptYn != "1"){
                $c.gus.cfDisableBtn([btn_Cancel, btn_Save, btn_AddRow, btn_DeleteRow, btn_UndoRow]);
			}else{
                $c.gus.cfDisableBtn([btn_Create, btn_Update, btn_AddRow, btn_DeleteRow, btn_UndoRow]);
			}
		}else{
            $c.gus.cfDisableBtn([btn_Update, btn_Cancel, btn_Save, btn_AddRow, btn_DeleteRow, btn_UndoRow]);
		}
        ds_user.setJSON([]);
        ds_userPrivGroup.setJSON([]);
        scwin.f_Retrieve();
	}
};

