scwin.gr_user_oncellclick = function (rowIndex, columnIndex, columnId) {
    let Row = rowIndex;
	if(scwin.flag == 1)	{
		if(lc_blockReason.getValue() == "")	{
			$c.gus.cfEnableObjects([lc_blockReason, ica_blockCancelEtDt, ica_blockEtDt, ica_blockDt]);
			$c.gus.cfDisableObjects([ica_blockDt]);
		}
	}

	// 선택된 Row가 변경되었는지를 확인한다.
	if(scwin.row_confirm != Row)	{
		if(scwin.row_confirm == "")
			ds_user.setCellData(Row, "newPasswd", "");
		ds_user.setCellData(scwin.row_confirm, "newPasswd", "");
		scwin.txt_newPasswdConfirm = "";
	}
	if( ds_user.getCellData(ds_user.getRowPosition(), "useYn") == 1)	{
		rd_useYn.setValue("1");
	}
	if( ds_user.getCellData(ds_user.getRowPosition(), "useYn") == 0)	{
		rd_useYn.setValue("0");
	}
	scwin.row_confirm = Row;
};

scwin.lc_blockReason_onchange = function (info) {
	if(scwin.flag == 1)	{	// 수정 상태
		ica_blockCancelEtDt.setValue("");
		ica_blockEtDt.setValue("");
		ica_blockDt.setValue("");

		$c.gus.cfDisableObjects([ica_blockDt, ica_blockCancelEtDt, ica_blockEtDt, lc_blockReason]);

		if(rd_useYn.getValue() == "0")	{
			if(lc_blockReason.getValue() == "A" || lc_blockReason.getValue() == "B")	{
				$c.gus.cfEnableObjects([ica_blockDt, ica_blockCancelEtDt,lc_blockReason]);
			}else if(lc_blockReason.getValue() == "C" || lc_blockReason.getValue() == "D")	{
				$c.gus.cfEnableObjects([lc_blockReason]);		
			}else if(lc_blockReason.getValue() == "E")	{
				$c.gus.cfEnableObjects([ica_blockDt, lc_blockReason]);
			}
		}
		if(rd_useYn.getValue() == "1")	{
			if(lc_blockReason.getValue() == "A" || lc_blockReason.getValue() == "B")	{
				$c.gus.cfEnableObjects([ ica_blockCancelEtDt, ica_blockEtDt,lc_blockReason]);
			}else if(lc_blockReason.getValue() == "C" || lc_blockReason.getValue() == "D")	{
				$c.gus.cfEnableObjects([lc_blockReason]);		
			}else if(lc_blockReason.getValue() == "E")	{
				$c.gus.cfEnableObjects([ica_blockEtDt, lc_blockReason]);
			}
		}		
	}
	else if(scwin.flag == 0)	{
		$c.gus.cfDisableObjects([ica_blockDt, ica_blockCancelEtDt, ica_blockEtDt, lc_blockReason]);
	}
};

