};

scwin.f_isUseYnChecked = function()	{

        if(scwin.flag == 1) 	{
            //if(ds_user.getRowStatus(ds_user.getRowPosition()) == 3)	{
            if(ds_user.getRowStatus(ds_user.getRowPosition()) ==  "U")	{
                lc_blockReason.setValue("");	
                ica_blockCancelEtDt.setValue("");	
                ica_blockEtDt.setValue("");	
                ica_blockDt.setValue("");	
            }
            else
            {
                lc_blockReason.setValue("");	
                ica_blockCancelEtDt.setValue("");	
                ica_blockEtDt.setValue("");	
                ica_blockDt.setValue("");	
            }
        }

        if(scwin.flag == 1)	{

            $c.gus.cfEnableObjects([lc_blockReason, ica_blockCancelEtDt, ica_blockEtDt, ica_blockDt]);
            if(rd_useYn.getValue() == "1")	{	
                $c.gus.cfDisableObjects([ica_blockDt]);
            }
            if(rd_useYn.getValue() == "0")	{
                if(lc_blockReason.getValue() == "A" || lc_blockReason.getValue() == "B")	{
                    $c.gus.cfDisableObjects([ica_blockEtDt]);
                }else if(lc_blockReason.getValue() == "C" || lc_blockReason.getValue() == "D" || lc_blockReason.getValue() == "E")	{
                    $c.gus.cfDisableObjects([ica_blockCancelEtDt, ica_blockEtDt]);
                }else	{
                    $c.gus.cfDisableObjects([ica_blockEtDt]);
                }
            }
        }	
};

scwin.tbl_search_onclick = function (e) {
    $c.gus.cfInitObjects(btn_search1_init);
    rd_useYn_param.setSelectedIndex(0);
    if( $p.getAllParameter().paramData.menuInfo.menuId.indexOf("n") > -1){
        rd_debis.setSelectedIndex(1);
    } else {
        rd_debis.setSelectedIndex(0);
    }
};

scwin.sbm_temp_submitdone = async function (e) {
    let vExistYn = ds_temp.getCellData(0, "userDupl");
    if (vExistYn != "0") { 				  
        scwin.txt_checkUserDupl = "";
        await $c.win.alert($c.data.getMessage(MSG_CM_WRN_011, "사용자ID"));
    } else {  
        await $c.win.alert($c.data.getMessage(MSG_CM_INF_015, "사용자ID"));
        scwin.txt_checkUserDupl = "1";
    }
};

scwin.sbm_temp2_submitdone = function (e) {
    if ( ds_temp.getRowCount() > 0 ) { 
        ed_userNm.setValue( ds_temp.get("userNm") ) ;
        ed_zip.setValue( ds_temp.get( "zip") );
        ed_addr1.setValue( ds_temp.get( "addr1") );
        ed_addr2.setValue( ds_temp.get( "addr2") );
        ed_acctDeptNm.setValue( ds_temp.get(  "acctDeptNm") );
        ed_empNo.setValue( ds_temp.get( "empNo") );
        if ( !$c.gus.cfIsNull( ed_empNo.getValue() ) ) ed_empNm.setValue( ds_temp.get( "userNm") ) ;
    } 
};

scwin.sbm_userPrivGroup_submitdone = function (e) {
    let rowCnt = ds_userPrivGroup.getRowCount();
    spanTotal2.setLabel(rowCnt);
    gr_userPrivGroup.setFocusedCell(0, "privGrpId");
};

scwin.rd_debis_onviewchange = function (info) {
    scwin.init();
};

scwin.sbm_email_submitdone = function (e) {
	let email = ds_email.getCellData(0,"col1");
	if ( email.indexOf("@") > 0 ) {
		ed_email.setValue(email);
    } else {
    	if (email != "") {
            ed_email.setValue( email + "@dongwon.com");
    	}
    }
};
